-- Owner 1 (محمد علي) - 8 apartments
('e1000000-0000-0000-0000-000000000001', 'b1000000-0000-0000-0000-000000000001', 'شقة مفروشة بالكامل في دلة', 'شقة راقية مفروشة بالكامل على بعد 5 دقائق من جامعة الفيوم. تحتوي على غرفة نوم مع سرير مزدوج، صالة معيشة، مطبخ مجهز بالكامل، حمام واحد مع سخان مياه. الشقة في عمارة آمنة مع مصعد.', 'Fayoum', 'Dallah', 'شارع جامعة، عمارة النور، الطابق الثالث', 3500.00, 'apartment', 2, 1, 95.00, true, true, true, true, ARRAY['واي فاي', 'تكييف', 'مطبخ مجهز', 'سخان مياه'], 245, true, true, 'approved', now() - interval '75 days', now() - interval '80 days'),

('e1000000-0000-0000-0000-000000000002', 'b1000000-0000-0000-0000-000000000001', 'غرفة مؤثثة في دلة', 'غرفة مفروشة بشكل أنيق مثالية لطالب واحد أو طالبة. تحتوي على سرير مفرد، مكتب دراسة، خزانة ملابس، حمام خاص. مدخل مستقل مع قفل إلكتروني.', 'Fayoum', 'Dallah', 'شارع الجلاء، عمارة الأمل', 1500.00, 'room', 1, 1, 25.00, true, true, true, false, ARRAY['واي فاي', 'سخان مياه'], 189, true, false, 'approved', now() - interval '70 days', now() - interval '78 days'),

('e1000000-0000-0000-0000-000000000003', 'b1000000-0000-0000-0000-000000000001', 'استوديو عصري في الحادقة', 'استوديو بتصميم عصري حديث يجمع بين الغرفة والمطبخ في مساحة واحدة أنيقة. يناسب الطلاب الباحثين عن الخصوصية. يطل على شارع هادئ.', 'Fayoum', 'El Hadqa', 'شارع الصفا، عمارة الريادة', 2800.00, 'studio', 1, 1, 45.00, true, true, true, true, ARRAY['واي فاي', 'تكييف', 'مطبخ مجهز'], 312, true, true, 'approved', now() - interval '65 days', now() - interval '76 days'),

('e1000000-0000-0000-0000-000000000004', 'b1000000-0000-0000-0000-000000000001', 'شقة مشتركة للطلاب في الحادقة', 'شقة مكونة من 3 غرف مشتركة مع صالة معيشة كبيرة ومطبخ مشترك ومنزلين. مناسبة لطلاب يبحثون عن سكن اقتصادي بجوار الجامعة.', 'Fayoum', 'El Hadqa', 'شارع النصر، عمارة السلام، الطابق الثاني', 1200.00, 'shared', 3, 2, 120.00, true, true, true, true, ARRAY['واي فاي', 'تكييف', 'مطبخ مجهز', 'غرفة معيشة'], 156, true, false, 'approved', now() - interval '60 days', now() - interval '72 days'),

('e1000000-0000-0000-0000-000000000005', 'b1000000-0000-0000-0000-000000000001', 'شقة فاخرة في دلة', 'شقة فاخرة بتشطيبات سوبر لوكس. 3 غرف نوم واسعة، صالة كبيرة، مطبخ أمريكي مجهز بالكامل، 2 حمام، بلكونة تطل على الحديقة. مناسبة لعائلات صغيرة.', 'Fayoum', 'Dallah', 'شارع الحرية، فيلا النخيل', 5500.00, 'apartment', 3, 2, 150.00, true, true, true, true, ARRAY['واي فاي', 'تكييف', 'مطبخ مجهز', 'شرفة', 'مصعد', 'سخان مياه'], 420, true, true, 'approved', now() - interval '55 days', now() - interval '68 days'),

('e1000000-0000-0000-0000-000000000006', 'b1000000-0000-0000-0000-000000000001', 'شقة في الجامعية', 'شقة في قلب حي الجامعية، على بعد خطوات من بوابة جامعة الفيوم الرئيسية. غرفتان نوم، صالة، مطبخ، حمام. مثالية للطلاب.', 'Fayoum', 'El Gamea', 'شارع الجامعة، عمارة الأبطال', 3000.00, 'apartment', 2, 1, 80.00, true, true, true, false, ARRAY['واي فاي', 'تكييف'], 298, true, false, 'approved', now() - interval '50 days', now() - interval '65 days'),

('e1000000-0000-0000-0000-000000000007', 'b1000000-0000-0000-0000-000000000001', 'شقة قيد المراجعة', 'شقة جديدة بإطلالة رائعة على النيل. قيد المراجعة من الإدارة.', 'Fayoum', 'El Masalla', 'شارع النيل، برج الإيمان', 4000.00, 'apartment', 2, 2, 110.00, true, true, true, true, ARRAY['واي فاي', 'تكييف', 'مطبخ مجهز'], 0, true, false, 'pending', NULL, now() - interval '5 days'),

