INSERT INTO reviews (user_id, apartment_id, rating, comment, created_at) VALUES
('d1000000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000001', 5, 'شقة ممتازة جداً! المكان نظيف والأثاث جديد. المالك محترم وسريع في الرد. أنصح بها بشدة.', now() - interval '60 days'),
('d1000000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000008', 4, 'شقة جيدة بشكل عام. الموقع ممتاز والثمن مناسب. المطبخ محتاج شوية تحسين.', now() - interval '55 days'),
('d1000000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000003', 5, 'أفضل استوديو في الفيوم! التصميم عصري والمكان مريح جداً. الواي فاي سريع.', now() - interval '50 days'),
('d1000000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000023', 4, 'استوديو آمن ومريح للطالبات. الحارس محترم والمكان نظيف. بس الصوت عالي من الشارع.', now() - interval '45 days'),
('d1000000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000006', 3, 'شقة عادية. الموقع ممتاز بس الأثاث قديم شوية. الحمام محتاج تجديد.', now() - interval '40 days'),
('d1000000-0000-0000-0000-000000000006', 'e1000000-0000-0000-0000-000000000016', 5, 'استوديو رائع! التكييف شغال ممتاز والمطبخ مجهز بالكامل. سعر مناسب جداً.', now() - interval '35 days'),
('d1000000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000005', 5, 'شقة فاخرة تستحق كل فلس. الإطلالة رائعة والتشطيبات سوبر لوكس.', now() - interval '30 days'),
('d1000000-0000-0000-0000-000000000007', 'e1000000-0000-0000-0000-000000000012', 4, 'شقة ممتازة في حي هادئ. مناسبة للدراسة. بس بعيدة شوية عن الجامعة.', now() - interval '25 days'),
('d1000000-0000-0000-0000-000000000008', 'e1000000-0000-0000-0000-000000000002', 4, 'غرفة صغيرة لكن نظيفة ومريحة. المالك محترم ومتعاون.', now() - interval '20 days'),
('d1000000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000018', 5, 'شقة ممتازة للعائلات. واسعة ومجهزة بالكامل. الحديقة أمام العمارة جميلة.', now() - interval '15 days');

